import java.util.ArrayList;

public class Main {

    static ArrayList<String> todoList = new ArrayList<>();

    static void showMenu() {
        System.out.println("\n=== YAPILACAKLAR LISTESI ===");
        System.out.println("1. Gorev Ekle");
        System.out.println("2. Gorevleri Listele");
        System.out.println("3. Gorev Sil");
        System.out.println("4. Cikis");
    }

    static void addTask(String task) {
        todoList.add(task);
        System.out.println("Eklendi: '" + task + "'");
    }

    static void listTasks() {
        if (todoList.isEmpty()) {
            System.out.println("Liste bos.");
            return;
        }

        for (int i = 0; i < todoList.size(); i++) {
            System.out.println((i + 1) + ". " + todoList.get(i));
        }
    }

    static void removeTask(int index) {
        if (index >= 0 && index < todoList.size()) {
            System.out.println("Silindi: '" + todoList.get(index) + "'");
            todoList.remove(index);
        } else {
            System.out.println("Gecersiz numara.");
        }
    }

    public static void main(String[] args) {
        showMenu();

        System.out.println("\n> Secim: 1");
        addTask("Markete git");

        System.out.println("\n> Secim: 1");
        addTask("Kod yaz");

        System.out.println("\n> Secim: 1");
        addTask("Spor yap");

        System.out.println("\n> Secim: 2");
        listTasks();

        System.out.println("\n> Secim: 3 (1. gorevi sil)");
        removeTask(0);

        System.out.println("\n> Secim: 2");
        listTasks();

        System.out.println("\n> Secim: 4");
        System.out.println("Programdan cikiliyor...");
    }
}
